    .OrderBy(m => m.GetParameters().Length);

foreach (var m in runMethods)
{
    var ps = m.GetParameters();
    var sig = string.Join(", ", ps.Select(p => $"{p.ParameterType.Name} {p.Name}"));
    Console.WriteLine($"  public Task<{m.ReturnType.Name}> {m.Name}({sig})");
}

Console.WriteLine("\n=== AIAgent.RunStreamingAsync Methods ===");
var streamMethods = aiAgent.GetMethods(BindingFlags.Public | BindingFlags.Instance)
    .Where(m => m.Name == "RunStreamingAsync" && !m.IsGenericMethod)
    .OrderBy(m => m.GetParameters().Length);

foreach (var m in streamMethods)
{
    var ps = m.GetParameters();
